"use client";

import { useState, useRef, useCallback, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, getRandomEncourage, triggerShake } from "@/lib/learningMessages";

interface SceneConfig {
  id: string;
  icon: string;
  title: string;
  question: string;
  svg: React.ReactNode;
  options: { key: string; text: string }[];
  correctFormula: string;
  correctAnswer: number;
  unit: string;
  animationClass: string;
}

const SCENES: SceneConfig[] = [
  {
    id: "fence",
    icon: "🌷",
    title: "围篱笆",
    question: "学校有一个长8米、宽5米的长方形花坛，要在四周围上篱笆，篱笆有多长？",
    svg: (
      <svg viewBox="0 0 200 140" className="mx-auto w-full max-w-[260px]">
        {/* 地面 */}
        <ellipse cx="100" cy="120" rx="90" ry="12" fill="var(--signal-pending)" opacity="0.3" />
        {/* 花坛主体 */}
        <rect x="40" y="30" width="120" height="80" rx="4" fill="#86efac" stroke="#22c55e" strokeWidth="2" />
        {/* 花朵 */}
        <circle cx="70" cy="55" r="6" fill="#f472b6" />
        <circle cx="70" cy="55" r="2" fill="#fbbf24" />
        <circle cx="130" cy="55" r="6" fill="#f472b6" />
        <circle cx="130" cy="55" r="2" fill="#fbbf24" />
        <circle cx="100" cy="80" r="6" fill="#a78bfa" />
        <circle cx="100" cy="80" r="2" fill="#fbbf24" />
        {/* 标注 */}
        <text x="100" y="22" textAnchor="middle" fontSize="12" fill="var(--text)">8米</text>
        <text x="28" y="72" textAnchor="middle" fontSize="12" fill="var(--text)">5米</text>
      </svg>
    ),
    options: [
      { key: "A", text: "(8+5)×2" },
      { key: "B", text: "8×5" },
      { key: "C", text: "8+5" },
      { key: "D", text: "8×2+5" },
    ],
    correctFormula: "A",
    correctAnswer: 26,
    unit: "米",
    animationClass: "fence",
  },
  {
    id: "table",
    icon: "🪑",
    title: "包桌子边",
    question: "一张正方形桌子边长70厘米，要给桌子包一圈防撞条，需要多长？",
    svg: (
      <svg viewBox="0 0 200 140" className="mx-auto w-full max-w-[260px]">
        {/* 地面 */}
        <ellipse cx="100" cy="120" rx="80" ry="10" fill="var(--signal-pending)" opacity="0.3" />
        {/* 桌腿 */}
        <rect x="55" y="85" width="8" height="28" rx="2" fill="#9ca3af" />
        <rect x="137" y="85" width="8" height="28" rx="2" fill="#9ca3af" />
        {/* 桌面 */}
        <rect x="40" y="30" width="120" height="60" rx="6" fill="#bfdbfe" stroke="#3b82f6" strokeWidth="2" />
        {/* 装饰 */}
        <circle cx="100" cy="60" r="12" fill="#93c5fd" opacity="0.5" />
        {/* 标注 */}
        <text x="100" y="22" textAnchor="middle" fontSize="12" fill="var(--text)">70厘米</text>
      </svg>
    ),
    options: [
      { key: "A", text: "70×4" },
      { key: "B", text: "70+4" },
      { key: "C", text: "70×70" },
      { key: "D", text: "70+70" },
    ],
    correctFormula: "A",
    correctAnswer: 280,
    unit: "厘米",
    animationClass: "table",
  },
  {
    id: "playground",
    icon: "🏃",
    title: "操场跑步",
    question: "操场长100米、宽60米，小明跑一圈是多少米？",
    svg: (
      <svg viewBox="0 0 200 140" className="mx-auto w-full max-w-[260px]">
        {/* 草地 */}
        <rect x="20" y="15" width="160" height="110" rx="6" fill="#bbf7d0" stroke="#86efac" strokeWidth="2" />
        {/* 跑道 */}
        <rect x="40" y="30" width="120" height="80" rx="4" fill="#e5e7eb" stroke="#9ca3af" strokeWidth="2" strokeDasharray="4 3" />
        {/* 标注 */}
        <text x="100" y="22" textAnchor="middle" fontSize="11" fill="var(--text)">100米</text>
        <text x="28" y="72" textAnchor="middle" fontSize="11" fill="var(--text)">60米</text>
        {/* 小人 */}
        <circle cx="65" cy="50" r="4" fill="#f59e0b" />
        <line x1="65" y1="54" x2="65" y2="64" stroke="#f59e0b" strokeWidth="2" />
        <line x1="60" y1="58" x2="70" y2="58" stroke="#f59e0b" strokeWidth="2" />
        <line x1="62" y1="68" x2="65" y2="64" stroke="#f59e0b" strokeWidth="2" />
        <line x1="68" y1="68" x2="65" y2="64" stroke="#f59e0b" strokeWidth="2" />
      </svg>
    ),
    options: [
      { key: "A", text: "(100+60)×2" },
      { key: "B", text: "100×60" },
      { key: "C", text: "100+60" },
      { key: "D", text: "100×2+60" },
    ],
    correctFormula: "A",
    correctAnswer: 320,
    unit: "米",
    animationClass: "playground",
  },
];

export default function ApplyPage() {
  const [sceneIdx, setSceneIdx] = useState(0);
  const [step, setStep] = useState<"formula" | "answer">("formula");
  const [selected, setSelected] = useState<string | null>(null);
  const [answer, setAnswer] = useState("");
  const [done, setDone] = useState<boolean[]>([false, false, false]);
  const [showAnim, setShowAnim] = useState(false);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const optionsRef = useRef<HTMLDivElement>(null);
  const answerRef = useRef<HTMLDivElement>(null);

  const scene = SCENES[sceneIdx];
  const allDone = done.every(Boolean);

  const handleSelect = useCallback(
    (key: string) => {
      if (key === scene.correctFormula) {
        setSelected(key);
        setTimeout(() => setStep("answer"), 400);
      } else {
        triggerShake(optionsRef.current);
        setSelected(null);
      }
    },
    [scene]
  );

  const handleAnswer = useCallback(() => {
    const val = parseInt(answer, 10);
    if (val === scene.correctAnswer) {
      setShowAnim(true);
      setTimeout(() => {
        const nextDone = [...done];
        nextDone[sceneIdx] = true;
        setDone(nextDone);
        setShowAnim(false);
        setSelected(null);
        setAnswer("");
        setStep("formula");
        if (sceneIdx < SCENES.length - 1) {
          setSceneIdx((p) => p + 1);
        }
      }, 2000);
    } else {
      triggerShake(answerRef.current);
    }
  }, [answer, scene, sceneIdx, done]);

  return (
    <StepShell topicId="perimeter" stepId="apply">
      <div className="space-y-6">
        {!allDone && (
          <section
            ref={scene.animationClass === "playground" && showAnim ? undefined : undefined}
            className="relative overflow-hidden rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]"
          >
            {/* 场景插图 + 题目 */}
            <div className="relative">
              {scene.svg}
              {/* 篱笆动画 */}
              {scene.id === "fence" && showAnim && (
                <svg
                  viewBox="0 0 200 140"
                  className="pointer-events-none absolute inset-0 mx-auto w-full max-w-[260px]"
                >
                  <rect
                    x="34"
                    y="24"
                    width="132"
                    height="92"
                    rx="6"
                    fill="none"
                    stroke="#a16207"
                    strokeWidth="3"
                    strokeDasharray="8 4"
                    className="animate-draw-border"
                  />
                </svg>
              )}
              {/* 防撞条动画 */}
              {scene.id === "table" && showAnim && (
                <svg
                  viewBox="0 0 200 140"
                  className="pointer-events-none absolute inset-0 mx-auto w-full max-w-[260px]"
                >
                  <rect
                    x="36"
                    y="26"
                    width="128"
                    height="68"
                    rx="8"
                    fill="none"
                    stroke="#ef4444"
                    strokeWidth="4"
                    className="animate-draw-border"
                  />
                </svg>
              )}
              {/* 跑步动画 */}
              {scene.id === "playground" && showAnim && (
                <svg
                  viewBox="0 0 200 140"
                  className="pointer-events-none absolute inset-0 mx-auto w-full max-w-[260px]"
                >
                  <rect
                    x="38"
                    y="28"
                    width="124"
                    height="84"
                    rx="4"
                    fill="none"
                    stroke="#f59e0b"
                    strokeWidth="2"
                    strokeDasharray="6 3"
                    className="animate-draw-border"
                  />
                  <circle r="5" fill="#f97316" className="animate-run-path" />
                </svg>
              )}
            </div>

            <div className="mt-4 text-center">
              <span className="inline-flex items-center gap-1 rounded-full bg-[var(--bg-soft)] px-3 py-1 text-xs font-medium text-[var(--text-secondary)]">
                {scene.icon} 场景 {sceneIdx + 1} / {SCENES.length}
              </span>
              <p className="mt-3 text-base font-medium text-[var(--text)]">{scene.question}</p>
            </div>

            {/* 步骤1：选择算式 */}
            {step === "formula" && (
              <div className="mt-6 space-y-4">
                <p className="text-center text-sm text-[var(--text-secondary)]">
                  第一步：选择正确的算式
                </p>
                <div ref={optionsRef} className="flex flex-wrap justify-center gap-3">
                  {scene.options.map((opt) => {
                    const isCorrect = selected === opt.key && opt.key === scene.correctFormula;
                    return (
                      <button
                        key={opt.key}
                        onClick={() => handleSelect(opt.key)}
                        className={`relative rounded-xl border-2 px-5 py-3 text-base font-bold transition-all ${
                          isCorrect
                            ? "border-[var(--signal-confirmed)] bg-[var(--signal-confirmed)]/20 text-[var(--text)]"
                            : "border-[var(--border)] bg-[var(--bg-soft)] text-[var(--text)] hover:border-[var(--primary)]/50"
                        }`}
                      >
                        <span className="mr-1 text-sm text-[var(--text-muted)]">{opt.key}:</span>
                        {opt.text}
                        {isCorrect && (
                          <span className="absolute -top-2 -right-2 flex h-6 w-6 items-center justify-center rounded-full bg-[var(--signal-confirmed)] text-xs text-white">
                            ✓
                          </span>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}

            {/* 步骤2：输入答案 */}
            {step === "answer" && (
              <div className="mt-6 space-y-4">
                <p className="text-center text-sm text-[var(--text-secondary)]">
                  第二步：算出结果是多少？
                </p>
                <div ref={answerRef} className="flex items-center justify-center gap-3">
                  <input
                    type="text"
                    inputMode="numeric"
                    value={answer}
                    onChange={(e) => setAnswer(e.target.value.replace(/[^0-9]/g, ""))}
                    onKeyDown={(e) => e.key === "Enter" && handleAnswer()}
                    className="w-28 rounded-xl border-2 border-[var(--border)] px-4 py-3 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    placeholder="?"
                    autoFocus
                  />
                  <span className="text-lg font-medium text-[var(--text)]">{scene.unit}</span>
                </div>
                <div className="text-center">
                  <button
                    onClick={handleAnswer}
                    disabled={!answer}
                    className="rounded-full bg-[var(--primary)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)] disabled:cursor-not-allowed disabled:opacity-40"
                  >
                    验证答案
                  </button>
                </div>
              </div>
            )}

            {/* 鼓励提示（仅在答错后出现） */}
            {!showAnim && step === "answer" && answer && (
              <p className="mt-2 text-center text-xs text-[var(--text-muted)]">
                提示：先确认算式，再仔细计算
              </p>
            )}
          </section>
        )}

        {/* 场景进度 */}
        {!allDone && (
          <div className="flex justify-center gap-2">
            {SCENES.map((s, i) => (
              <div
                key={s.id}
                className={`h-2.5 flex-1 max-w-[80px] rounded-full transition-all ${
                  done[i]
                    ? "bg-[var(--signal-confirmed)]"
                    : i === sceneIdx
                      ? "bg-[var(--primary)]"
                      : "bg-[var(--signal-pending)]"
                }`}
              />
            ))}
          </div>
        )}

        {/* 完成卡片 */}
        {allDone && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-confirmed)] bg-[var(--bg-card)] p-8 text-center shadow-[var(--shadow-md)]">
              <div className="text-5xl animate-bounce-soft">🎉</div>
              <h2 className="mt-4 text-xl font-bold text-[var(--text)]">{completeMsg}</h2>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                你帮学校算好了篱笆、桌边和操场的周长，真厉害！
              </p>
              <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
                <Link
                  href="/learn/perimeter"
                  className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
                >
                  ← 回到周长主页
                </Link>
                <Link
                  href="/learn/perimeter/discover"
                  className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
                >
                  下一步：总结公式 →
                </Link>
              </div>
            </section>
          </div>
        )}
      </div>

      <style jsx>{`
        @keyframes draw-border {
          from {
            stroke-dashoffset: 500;
          }
          to {
            stroke-dashoffset: 0;
          }
        }
        .animate-draw-border {
          stroke-dasharray: 500;
          stroke-dashoffset: 500;
          animation: draw-border 1.5s ease-out forwards;
        }
        @keyframes run-path {
          0% {
            offset-distance: 0%;
          }
          100% {
            offset-distance: 100%;
          }
        }
        .animate-run-path {
          offset-path: path("M 40 30 L 160 30 L 160 110 L 40 110 Z");
          animation: run-path 1.8s linear forwards;
        }
      `}</style>
    </StepShell>
  );
}
